function solve(nums, queries) {
    const results = [];
    const N = nums.length;

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify the set of removed even numbers in nums[l..r]
        const removedEvens = new Set();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            // Check if num is even and positive (nums[i] >= 1)
            if (num % 2 === 0) {
                removedEvens.add(num);
            }
        }

        // 2. Binary search for the k-th remaining positive even number (X)
        // The sequence of all positive even numbers is 2, 4, 6, 8, ...
        // The n-th positive even number is 2*n.
        // We are looking for the smallest X = 2*n such that the count of remaining evens <= X is at least k.

        // Search range for the answer X: [2, MaxPossibleAnswer]
        // MaxPossibleAnswer needs to be large enough. Since k <= 10^9, the k-th smallest positive even number is 2*10^9.
        // Even if all small evens are removed, the answer won't exceed a reasonable bound based on k.
        // Let's set a safe upper bound, e.g., 2 * 10^14 to handle large k, although 2*10^9 might suffice for k<=10^9.
        // Since nums[i] <= 10^9, the maximum number removed is 10^9. The k-th number could be around 2*k.
        // A safe upper bound: 2 * (k + N) is overkill, 2 * k + 2*N should be enough.
        // Let's use a generous upper bound like 4 * 10^14, which fits within standard JS number safety range for comparison if we use BigInt, but we stick to standard numbers for the search boundary unless necessary.
        // Since k <= 10^9, 2k <= 2*10^9. Let's use 4 * 10^9 as a practical upper bound if we assume the answer won't be astronomically large beyond k.

        // Let's use 2 * 10^14 as a very safe upper limit for the binary search range for X, which is 2*n. n <= 10^14.
        // JavaScript numbers safely represent integers up to 2^53 - 1 (~9 * 10^15).
        let low = 2;
        let high = 4e14; // Safe upper bound for X = 2*n, where n can be up to 2*10^14
        let ans = high;

        while (low <= high) {
            const mid = Math.floor((low + high) / 2); // mid is the potential answer X = 2*n

            // Count how many positive even numbers <= mid are NOT in removedEvens.

            // Total count of positive even numbers <= mid is mid / 2.
            const totalEvens = Math.floor(mid / 2);

            // Count how many removed evens <= mid are present in removedEvens.
            let removedCount = 0;
            for (const removed of removedEvens) {
                if (removed <= mid) {
                    removedCount++;
                }
            }

